/**
 * @name Library name/version taint flow to FilePath or cache directory operations
 * @description Tracks library name/version from user-controlled input to file path operations
 * @kind path-problem
 * @problem.severity error
 * @id java/library-name-to-filepath
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Sources: library name/version from @Library annotation or library step parameters
module LibNameConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getName() calls on LibraryConfiguration or Library annotation
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getName") or
        mc.getMethod().hasName("getVersion") or
        mc.getMethod().hasName("getDefaultVersion")
      ) and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.workflow.libs", "LibraryConfiguration") or
        mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.workflow.libs", "LibraryRecord") or
        mc.getMethod().getDeclaringType().hasQualifiedName("org.jenkinsci.plugins.workflow.libs", "LibraryCachingConfiguration")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // FilePath construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FilePath.child() calls
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // String concatenation used in path construction passed to exec
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module LibNameFlow = TaintTracking::Global<LibNameConfig>;
import LibNameFlow::PathGraph

from LibNameFlow::PathNode source, LibNameFlow::PathNode sink
where LibNameFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Library name/version flows to file path from $@.", source.getNode(), "library config"

/**
 * @name Library version used as git refspec or branch in SCM operations
 * @description Detects library version (user-controlled) being used directly as git branch/tag/refspec
 * @kind path-problem
 * @problem.severity error
 * @id java/library-version-git-refspec
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-077
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module GitRefspecConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // version parameter in retrieve() methods
    exists(Parameter p |
      p.getCallable().hasName("retrieve") and
      p.getCallable().getDeclaringType().getPackage().getName().matches("org.jenkinsci.plugins.workflow.libs%") and
      (p.getName() = "version" or p.getName() = "libName" or p.getName() = "name") and
      source.asParameter() = p
    )
    or
    // version parameter in doRetrieve() methods
    exists(Parameter p |
      p.getCallable().hasName("doRetrieve") and
      p.getCallable().getDeclaringType().getPackage().getName().matches("org.jenkinsci.plugins.workflow.libs%") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // FilePath.child() - path traversal risk
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // SCMHead/Branch/Tag construction
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().getName().matches("%Branch%") or
        ce.getConstructor().getDeclaringType().getName().matches("%Tag%") or
        ce.getConstructor().getDeclaringType().getName().matches("%SCMHead%")
      ) and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // fetch/retrieve calls
    exists(MethodCall mc |
      (mc.getMethod().hasName("fetch") or mc.getMethod().hasName("checkout")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module GitRefspecFlow = TaintTracking::Global<GitRefspecConfig>;
import GitRefspecFlow::PathGraph

from GitRefspecFlow::PathNode source, GitRefspecFlow::PathNode sink
where GitRefspecFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Library version/name parameter '$@' flows to SCM or path operation.", source.getNode(), "version/name parameter"

/**
 * @name Library version flowing to SCMHead/Branch construction for git checkout
 * @description Library version string (user-controlled) used to construct SCM branch/tag names 
 *              without sanitization, enabling argument injection into git operations
 * @kind path-problem
 * @problem.severity error
 * @id java/library-version-branch-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module BranchInjConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // version parameter in retrieve methods - this is user-controlled library version
    exists(Parameter p |
      (
        p.getCallable().hasName("retrieve") or
        p.getCallable().hasName("doRetrieve")
      ) and
      p.getCallable().getDeclaringType().getPackage().getName().matches("org.jenkinsci.plugins.workflow.libs%") and
      source.asParameter() = p
    )
    or
    // LibraryAdder.retrieve - name is user-controlled library name 
    exists(Parameter p |
      p.getCallable().hasName("retrieve") and
      p.getCallable().getDeclaringType().getName() = "LibraryAdder" and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // SCMSourceRetriever.doRetrieve - version used for Branch/Tag name construction
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().getName().matches("%Branch%") or
        ce.getConstructor().getDeclaringType().getName().matches("%Tag%") or
        ce.getConstructor().getDeclaringType().getName().matches("%Head%")
      ) and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // SCMSource.fetch() with version as branch/tag argument
    exists(MethodCall mc |
      mc.getMethod().hasName("fetch") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("jenkins.scm.api", "SCMSource") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FilePath.child with name as directory component
    exists(MethodCall mc |
      mc.getMethod().hasName("child") and
      mc.getMethod().getDeclaringType().hasQualifiedName("hudson", "FilePath") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module BranchInjFlow = TaintTracking::Global<BranchInjConfig>;
import BranchInjFlow::PathGraph

from BranchInjFlow::PathNode source, BranchInjFlow::PathNode sink
where BranchInjFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Library version/name from $@ used unsanitized in SCM branch/path operation.", source.getNode(), "retrieve parameter"
